import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"Upgrading","description":"","frontmatter":{},"headers":[],"relativePath":"admin/upgrading.md","filePath":"admin/upgrading.md","lastUpdated":1783546178000}'),r={name:"admin/upgrading.md"};function o(l,e,s,d,p,c){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="upgrading" tabindex="-1">Upgrading <a class="header-anchor" href="#upgrading" aria-label="Permalink to &quot;Upgrading&quot;">​</a></h1><p>Upgrade prokube with the release-specific instructions for the target version. Do not use backup and restore as a version-upgrade mechanism unless a release explicitly documents that path.</p><h2 id="before-upgrading" tabindex="-1">Before Upgrading <a class="header-anchor" href="#before-upgrading" aria-label="Permalink to &quot;Before Upgrading&quot;">​</a></h2><p>Prepare the upgrade as an operational change:</p><ul><li>read the release notes and migration notes for every skipped version;</li><li>verify the target Kubernetes version and component compatibility;</li><li>confirm a recent successful backup and restore procedure;</li><li>check cluster health, node capacity, and storage capacity;</li><li>pause or drain user workloads where required by the release notes;</li><li>identify the GitOps repository, branch, and Argo CD applications that control the deployment.</li></ul><h2 id="gitops-managed-deployments" tabindex="-1">GitOps-Managed Deployments <a class="header-anchor" href="#gitops-managed-deployments" aria-label="Permalink to &quot;GitOps-Managed Deployments&quot;">​</a></h2><p>In GitOps-managed deployments, upgrade by changing the authoritative deployment configuration, not by patching live resources manually.</p><p>Typical flow:</p><ol><li>Create an upgrade branch from the deployment repository.</li><li>Apply the release-specific changes.</li><li>Review generated manifests and environment overlays.</li><li>Merge or push through the deployment&#39;s normal approval path.</li><li>Refresh and sync the affected Argo CD applications.</li><li>Watch reconciliation, pods, jobs, and application health until the platform is stable.</li></ol><p>Avoid force pushes and live hotfixes unless the deployment runbook explicitly requires them and the rollback path is clear.</p><h2 id="kubernetes-and-node-upgrades" tabindex="-1">Kubernetes and Node Upgrades <a class="header-anchor" href="#kubernetes-and-node-upgrades" aria-label="Permalink to &quot;Kubernetes and Node Upgrades&quot;">​</a></h2><p>Kubernetes or node upgrades can affect stateful workloads and <code>ReadWriteOnce</code> volumes. Before draining nodes, check for Labs, database pods, MinIO pods, MLflow components, and model-serving workloads with local or node-bound storage.</p><p>If a pod cannot move during a drain, inspect:</p><ul><li>PVC access mode and topology;</li><li>pod disruption budgets;</li><li>node selectors and affinities;</li><li>GPU or local-storage constraints;</li><li>controller reconciliation status.</li></ul><p>Do not delete stuck stateful pods or volumes to force progress unless the storage and application recovery implications are understood.</p><h2 id="after-upgrading" tabindex="-1">After Upgrading <a class="header-anchor" href="#after-upgrading" aria-label="Permalink to &quot;After Upgrading&quot;">​</a></h2><p>Validate user-facing and admin paths:</p><ul><li>login and workspace selection;</li><li>Labs start/stop and volume mounting;</li><li>object storage browser and S3 access;</li><li>Pipelines submission and run logs;</li><li>MLflow login, tracking, and artifact access;</li><li>Model Serving deployment and endpoint testing;</li><li>System Status, Grafana, Prometheus, Loki, and Alertmanager;</li><li>backup jobs and monitoring alerts.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./backup_restore.html">Backup and Restore</a></li><li><a href="./installation.html">Installation Planning</a></li><li><a href="./operations_runbooks.html">Operations Runbooks</a></li></ul>',20)])])}const h=a(r,[["render",o]]);export{g as __pageData,h as default};
